const stations = ['Aluva','Pulinchodu','Companypady','Ambattukavu','Muttom','Kalamassery','Cochin University','Pathadipalam','Edappally','Changampuzha Park','Palarivattom','JLN Stadium','Kaloor','Lissie','MG Road','Maharaja’s College','Ernakulam South','Kadavanthra','Elamkulam','Vyttila','Thaikoodam','Petta','Vadakkekotta','SN Junction','Tripunithura'];
const aliases = {'edapally':'Edappally','edappaly':'Edappally','m g road':'MG Road','mgroad':'MG Road','maharajas':'Maharaja’s College','maharajas college':'Maharaja’s College','ernakulam south':'Ernakulam South','south':'Ernakulam South','jln':'JLN Stadium','stadium':'JLN Stadium','sn junction':'SN Junction','tripunithura terminal':'Tripunithura'};
const norm = s => String(s || '').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();
const q = norm(query.station); const exact = aliases[q] || stations.find(s => norm(s) === q);
if (exact) return JSON.stringify({resolved: exact, confidence: 'high'});
const score = s => { const a=norm(s); let m=0; for (const c of q) if(a.includes(c)) m++; return m/Math.max(a.length,q.length,1); };
const candidates = stations.map(s=>({station:s,score:score(s)})).sort((a,b)=>b.score-a.score).slice(0,3);
return JSON.stringify({resolved: candidates[0]?.score >= 0.45 ? candidates[0].station : null, confidence: candidates[0]?.score >= 0.7 ? 'medium':'low', candidates});

const input = $input.first().json;
const pre = $('Execute Workflow Trigger').first().json;

function parseMaybeJson(value) {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  try { return JSON.parse(trimmed); } catch (e) { return value; }
}

function extractReply(value) {
  const parsed = parseMaybeJson(value);
  if (typeof parsed === 'string') return parsed;
  if (Array.isArray(parsed)) {
    for (const item of parsed) {
      const found = extractReply(item?.json ?? item);
      if (found) return found;
    }
    return null;
  }
  if (parsed && typeof parsed === 'object') {
    if (typeof parsed.replyMessage === 'string') return parsed.replyMessage;
    if (typeof parsed.output === 'string' && parsed.output.includes('MetroMind Trip Plan')) return parsed.output;
    if (parsed.json) return extractReply(parsed.json);
    if (parsed.data) return extractReply(parsed.data);
  }
  return null;
}

function planTripObservationReply(agentOutput) {
  const candidates = [agentOutput.intermediateSteps, agentOutput.intermediate_steps, agentOutput.steps, agentOutput.intermediateStepsJson].filter(Boolean);
  for (const rawSteps of candidates) {
    const steps = parseMaybeJson(rawSteps);
    if (!Array.isArray(steps)) continue;
    for (const step of steps) {
      const toolName = String(step?.action?.tool ?? step?.tool ?? step?.toolName ?? '').toLowerCase();
      if (!toolName.includes('plan') && !toolName.includes('trip')) continue;
      const reply = extractReply(step.observation ?? step.output ?? step.result ?? step.response);
      if (reply) return reply;
    }
  }
  return null;
}

const protectedTripReply = planTripObservationReply(input);
const message = String(protectedTripReply ?? input.output ?? 'Sorry, I could not prepare a response. Please try again.').trim();

return [{
  json: {
    phoneNumber: pre.phoneNumber,
    outboundMessage: message.slice(0, 1500),
    loggedAt: $now.toISO(),
    userMessage: pre.userMessage,
    responseTimeMs: Date.now() - new Date(pre.receivedAt).getTime(),
    intent: protectedTripReply ? 'trip_plan_tool_response' : 'assistant_response',
    origin: '',
    destination: ''
  }
}];
